function solve(nums) {
    const n = nums.length;
    if (n === 1) return 0;

    // Precompute primes up to the maximum number in nums using Sieve of Eratosthenes
    const maxNum = Math.max(...nums);
    const isPrime = new Array(maxNum + 1).fill(true);
    isPrime[0] = isPrime[1] = false;
    for (let i = 2; i * i <= maxNum; i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= maxNum; j += i) {
                isPrime[j] = false;
            }
        }
    }

    // Build a map from prime to all indices divisible by that prime
    const primeToIndices = new Map();
    for (let i = 0; i < n; i++) {
        const num = nums[i];
        if (num === 1) continue;
        if (isPrime[num]) {
            if (!primeToIndices.has(num)) {
                primeToIndices.set(num, []);
            }
            primeToIndices.get(num).push(i);
        } else {
            // Check all prime factors of num
            let temp = num;
            for (let p = 2; p * p <= temp; p++) {
                if (temp % p === 0) {
                    if (isPrime[p]) {
                        if (!primeToIndices.has(p)) {
                            primeToIndices.set(p, []);
                        }
                        primeToIndices.get(p).push(i);
                    }
                    while (temp % p === 0) {
                        temp /= p;
                    }
                }
            }
            if (temp > 1 && isPrime[temp]) {
                if (!primeToIndices.has(temp)) {
                    primeToIndices.set(temp, []);
                }
                primeToIndices.get(temp).push(i);
            }
        }
    }

    const queue = [[0, 0]];
    const visited = new Set();
    visited.add(0);

    while (queue.length > 0) {
        const [current, steps] = queue.shift();
        if (current === n - 1) {
            return steps;
        }

        // Move to adjacent indices
        const neighbors = [];
        if (current + 1 < n) neighbors.push(current + 1);
        if (current - 1 >= 0) neighbors.push(current - 1);

        for (const neighbor of neighbors) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                queue.push([neighbor, steps + 1]);
            }
        }

        // Check if current index is a prime or has prime factors
        const num = nums[current];
        if (num === 1) continue;

        let primes = [];
        if (isPrime[num]) {
            primes.push(num);
        } else {
            // Get all prime factors of num
            let temp = num;
            for (let p = 2; p * p <= temp; p++) {
                if (temp % p === 0) {
                    if (isPrime[p]) {
                        primes.push(p);
                    }
                    while (temp % p === 0) {
                        temp /= p;
                    }
                }
            }
            if (temp > 1 && isPrime[temp]) {
                primes.push(temp);
            }
        }

        for (const p of primes) {
            if (primeToIndices.has(p)) {
                const indices = primeToIndices.get(p);
                for (const j of indices) {
                    if (j !== current && !visited.has(j)) {
                        visited.add(j);
                        queue.push([j, steps + 1]);
                    }
                }
            }
        }
    }

    return -1; // Shouldn't reach here if n >= 1
}

