import java.util.*

fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n == 1L) return 0

    val maxNum = nums.maxOrNull() ?: 0
    val isPrime = BooleanArray(maxNum.toInt() + 1) { true }
    isPrime[0] = false
    isPrime[1] = false
    for (i in 2..maxNum.toInt()) {
        if (isPrime[i]) {
            var j = i * i
            while (j <= maxNum.toInt()) {
                isPrime[j] = false
                j += i
            }
        }
    }

    val primeToIndices = mutableMapOf<Long, MutableList<Int>>()
    for (i in nums.indices) {
        var num = nums[i]
        if (num == 1L) continue
        if (isPrime[num.toInt()]) {
            primeToIndices.getOrPut(num) { mutableListOf() }.add(i)
        } else {
            var temp = num
            var p = 2L
            while (p * p <= temp) {
                if (temp % p == 0L) {
                    if (isPrime[p.toInt()]) {
                        primeToIndices.getOrPut(p) { mutableListOf() }.add(i)
                    }
                    while (temp % p == 0L) {
                        temp /= p
                    }
                }
                p++
            }
            if (temp > 1 && isPrime[temp.toInt()]) {
                primeToIndices.getOrPut(temp) { mutableListOf() }.add(i)
            }
        }
    }

    val queue: Queue<Pair<Int, Long>> = LinkedList()
    queue.add(0 to 0L)
    val visited = BooleanArray(n) { false }
    visited[0] = true

    while (queue.isNotEmpty()) {
        val (current, steps) = queue.poll()
        if (current == n - 1) {
            return steps
        }

        // Move to adjacent indices
        if (current + 1 < n && !visited[current + 1]) {
            visited[current + 1] = true
            queue.add(current + 1 to steps + 1)
        }
        if (current - 1 >= 0 && !visited[current - 1]) {
            visited[current - 1] = true
            queue.add(current - 1 to steps + 1)
        }

        // Check if current index is a prime or has prime factors
        val num = nums[current]
        if (num == 1L) continue

        val primes = mutableListOf<Long>()
        if (isPrime[num.toInt()]) {
            primes.add(num)
        } else {
            var temp = num
            var p = 2L
            while (p * p <= temp) {
                if (temp % p == 0L) {
                    if (isPrime[p.toInt()]) {
                        primes.add(p)
                    }
                    while (temp % p == 0L) {
                        temp /= p
                    }
                }
                p++
            }
            if (temp > 1 && isPrime[temp.toInt()]) {
                primes.add(temp)
            }
        }

        for (p in primes) {
            primeToIndices[p]?.forEach { j ->
                if (j != current && !visited[j]) {
                    visited[j] = true
                    queue.add(j to steps + 1)
                }
            }
        }
    }

    return -1
}
